import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { PromotionNotificationService } from '../../services/promotion-notification.service';
import { AuthService } from '../../services/Base/auth.service';

// Interfaccia per i dati uniti (notifica + promozione + ristorante)
export interface UserPromotion {
  notification_id: string;
  sent_at: string;
  promotion: {
    id: string;
    name: string;
    description: string | null;
    image_url: string | null;
    type: string;               // 'percentage' | 'fixed_amount' | ...
    discount_value: number;
    max_discount_amount: number | null;
    valid_from: string;
    valid_until: string | null;
    min_order_amount: number | null;
  };
  restaurant: {
    id: string;
    name: string;
    logo_url: string | null;
  };
}

@Component({
  selector: 'app-user-promotions',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './user-promotions.component.html',
  styleUrls: ['./user-promotions.component.css']
})
export class UserPromotionsComponent implements OnInit {
  private promoNotifService = inject(PromotionNotificationService);
  private authService = inject(AuthService);

  promotions: UserPromotion[] = [];
  loading = false;
  error: string | null = null;

  async ngOnInit() {
    if (!this.authService.currentUserValue) {
      this.error = 'Devi essere autenticato';
      return;
    }
    await this.loadPromotions();
  }

  async loadPromotions() {
    this.loading = true;
    this.error = null;
    try {
      // getMyPromotions() deve essere aggiunto al PromotionNotificationService
      this.promotions = await this.promoNotifService.getMyPromotions();
    } catch (err: any) {
      this.error = err.message || 'Errore nel caricamento delle promozioni';
      console.error(err);
    } finally {
      this.loading = false;
    }
  }

  formatDiscount(promotion: UserPromotion['promotion']): string {
    if (promotion.type === 'percentage') {
      let text = `${promotion.discount_value}%`;
      if (promotion.max_discount_amount) {
        text += ` (max ${promotion.max_discount_amount}€)`;
      }
      return text;
    } else {
      return `${promotion.discount_value}€`;
    }
  }

  isExpired(validUntil: string | null): boolean {
    if (!validUntil) return false;
    return new Date(validUntil) < new Date();
  }

  usePromotion(promotion: UserPromotion['promotion']) {
    // Logica per utilizzare la promozione (es. navigare al ristorante, applicare al carrello)
    console.log('Usa promozione', promotion);
    // Esempio: this.router.navigate(['/restaurant', promotion.restaurant_id]);
  }
}